CLUSTER:
[
 {
  "riskId": "risk.structure-independence.colo-denominator-mispricing-enterprise-geography",
  "title": "Colo-MW geo weights misprice the enterprise third of the cube: NL inflated, Swiss and German enterprise demand invisible by construction",
  "narrative": "Every geography share was apportioned on Statista's colocation-and-scale-colocation MW. But the segment axis says 29% of the market is enterprise on-premise — capacity that the colo denominator does not count at all. The error is not random: Switzerland's installed base including self-operated capacity is ~3x its colo figure, and Germany's installed IT load (BMWK >2,700 MW) far exceeds its 1,737 MW colo figure, while the Netherlands' weight reflects the Amsterdam colo hub, not Dutch enterprise demand. So the funnel multiplies an enterprise segment share by geo weights that systematically inflate NL×enterprise and starve CH×enterprise and DE×enterprise. Country sequencing, channel coverage and SAM built on these weights are wrong for a third of the market — and the mismatch is invisible because the summed shares still equal 1.0.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "All seven geo nodes are derived from a single colocation-scoped table whose country figures don't reconcile with other benchmarks (summed Statista colo exceeds CBRE's total European capacity), and no second vendor uses the same scope",
    "refs": [
     "digest:geo-region-denominator#c0",
     "digest:geo-region-denominator#c1",
     "digest:geo-region-denominator#c3"
    ]
   },
   {
    "step": "propagation",
    "text": "The segment axis includes enterprise on-prem at 0.29, but enterprise capacity is exactly what colo MW excludes: Switzerland is self-operation-heavy (colo 274 MW vs ~850 MW installed base) and Germany's installed load exceeds its colo figure by ~1,000 MW — the geo weights are the wrong measure for the enterprise slice by construction",
    "refs": [
     "ledger:seg.enterprise",
     "ledger:geo.CH",
     "ledger:geo.DE"
    ]
   },
   {
    "step": "model-impact",
    "text": "NL's 0.28 — a colo-hub weight — is applied to enterprise demand it doesn't represent, while CH's 0.08 understates a self-operation-heavy market; ~29% of TAM is misallocated across countries, distorting SAM reach and the country entry order",
    "refs": [
     "ledger:geo.NL",
     "ledger:serviceableFactor"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "National installed-IT-load figures published alongside colo figures",
    "where": "BMWK German data-centre landscape updates; CBRE Suisse commercial vs self-operated capacity reports",
    "threshold": "Installed-load country shares diverging >5pp from the model's colo-based shares",
    "updates": "increases"
   },
   {
    "signal": "Statista vs CBRE scope reconciliation for 2025/2026 vintages",
    "where": "CBRE Europe Data Centres quarterly vs Statista colocation-by-country table updates",
    "threshold": "Gap between summed Statista country colo and CBRE European totals persisting or widening",
    "updates": "increases"
   }
  ],
  "judgeTotal": 18,
  "distinctByJudge": "The core insight — that geo.NL's 'triangulated' green status certifies precision of the wrong denominator, and that the error is invisible because shares still sum to 1.0 — is genuinely hidden by surface appearance. Held below 4 because the ledger's own cross-checks already show CH (0.08 vs 0.13) and DE (0.42 vs 0.53) diverging by scope, so a careful reader had a thread to pull."
 },
 {
  "riskId": "risk.definition-scopedown.colo-scope-geography-misallocation",
  "title": "Apportioning all-segment TAM by colocation MW plants 29% of the market in the wrong countries — and the Year-1 channel plan inherits the error",
  "narrative": "The geo split apportions the entire TAM — including the 29% enterprise on-premise segment — by colocation MW. But enterprise PDU demand follows installed IT load, not colo halls, and the two geographies diverge sharply in CE: Germany's installed load (BMWK >2,700MW) dwarfs its colo figure (1,737MW), Switzerland is famously self-operation-heavy (850MW installed vs 274MW colo), while the Netherlands is the mirror image — an Amsterdam colo hub with a thin enterprise base. The ledger's own cross-checks show exactly this (DE 0.50 colo vs 0.42 installed; CH 0.08 vs 0.13) and then average past it. For a venture whose first-year channel is 'large operators' concentrated in Frankfurt and Amsterdam, the model quietly relocates a third of the TAM into the two metros it happens to be targeting — flattering the reachable share while the real enterprise demand sits in Swiss banks, Austrian utilities, and Polish industrials the channel never touches.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "The geo dimension uses a single colo-MW apportionment for all segments, but 29% of the TAM is enterprise on-premise whose geography follows installed load — and EUDCA confirms roughly one-third of Europe's IT power is outside commercial colo/hyperscale",
    "refs": [
     "ledger:seg.enterprise",
     "digest:geo-region-denominator#c9",
     "ledger:geo.DE"
    ]
   },
   {
    "step": "propagation",
    "text": "Where colo and installed scopes diverge, the ledger's own cross-checks disagree systematically: DE 0.50 (colo) vs 0.42 (BMWK installed), CH 0.08 vs 0.13 (self-operated-inclusive), PL 0.07 vs 0.10 (Mordor installed) — the colo lens over-weights the Amsterdam/Frankfurt hub countries and under-weights self-operation-heavy markets",
    "refs": [
     "ledger:geo.DE",
     "ledger:geo.CH",
     "ledger:geo.PL",
     "ledger:geo.NL"
    ]
   },
   {
    "step": "model-impact",
    "text": "Blending the enterprise 29% on an installed-load geography shifts the mix out of NL and DE toward CH and PL; the venture's operator-first channel (Frankfurt/Amsterdam colo) then covers a smaller true share of the TAM than the current split implies, compressing the reachable slice behind serviceableFactor",
    "refs": [
     "profile:Who is the primary buyer you'll sell through first?",
     "ledger:serviceableFactor",
     "ledger:cust.operator-large"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Share of CE rack-PDU demand originating from enterprise/self-operated sites vs colo fit-outs",
    "where": "BMWK annual 'German data centre landscape' update (installed vs colo split); CBRE Suisse commercial-vs-self-operated capacity report",
    "threshold": "Enterprise/self-operated share of national capacity holding >35% in DE/CH",
    "updates": "increases"
   },
   {
    "signal": "Where early inbound demand actually comes from during launch",
    "where": "Venture's own CRM geography vs the model's geo weights; distributor sell-through reports from CE master distributors",
    "threshold": "≥30% of qualified pipeline from outside DE+NL within 6 months",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "The individual cross-checks are already in the ledger and bracketed in bands, but the risk's whyMissable names the genuinely new insight: all four scope errors are correlated in the same direction and interact with the segment split and channel choice across different ledger dimensions. A careful founder reviewing node-by-node could plausibly still miss the cross-dimensional aggregation, though the raw divergences were visible."
 },
 {
  "riskId": "risk.boundary-substitution.nl-selfbuild-hotspot-hollows-geo",
  "title": "The Netherlands is CE's hyperscale self-build hotspot — its 28% geography weight counts MW that carry the least PDU content in the region",
  "narrative": "The geo split apportions tamBase by colo MW as if every megawatt carries equal PDU spend. But CBRE places ~60% of Europe's operational hyperscaler self-build capacity in Ireland, the Netherlands, Sweden and Belgium — and NL is the only CE-7 country on that list. Self-build halls are precisely where busway + OCP power-shelf architectures are set as default, and Amsterdam (70% of NL colo) is where those same hyperscale tenants lease wholesale suites. So the NL slice is disproportionately composed of substitution-leading capacity, while Germany's mix skews toward colo/enterprise halls that still buy PDUs. The model's 0.28 NL weight silently assumes PDU intensity is geography-neutral; in CE it is not, and the error concentrates in the second-largest geography node.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "CBRE: ~60% of Europe's operational hyperscaler self-build capacity is located in Ireland, Netherlands, Sweden and Belgium (Q4 2025) — NL is the sole CE-7 member, and European self-build is growing 24% YoY, faster than colocation's 19%",
    "refs": [
     "digest:seg-mix#c16",
     "digest:seg-mix#c14",
     "digest:seg-mix#c15"
    ]
   },
   {
    "step": "propagation",
    "text": "Self-build hyperscale halls are the architecture-setting sites for busway/shelf distribution; combined with Amsterdam's ~70% concentration of NL colo capacity absorbed heavily by hyperscale tenants, NL MW carry systematically lower discrete-PDU content per MW than DE or CH MW",
    "refs": [
     "ledger:geo.NL",
     "digest:seg-mix#c24"
    ]
   },
   {
    "step": "model-impact",
    "text": "geo.NL's 0.28 is derived purely from MW apportionment (951/3,451) with a band (0.24–0.31) that only reflects capacity-count uncertainty, not PDU-intensity variation; the PDU-euro share of NL is below its capacity share, overstating the NL slice of tamBase in absolute terms",
    "refs": [
     "ledger:geo.NL",
     "ledger:tamBase"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Rack-power architecture in new Amsterdam-region and North Holland build permits and fit-out tenders",
    "where": "TenderNed (Dutch national tender portal); Dutch Data Center Association 'State of the Dutch Data Centers' annual report",
    "threshold": "≥2 new NL builds specifying busway/shelf distribution as base design",
    "updates": "increases"
   },
   {
    "signal": "NL share of European hyperscaler self-build pipeline",
    "where": "CBRE European Data Centres quarterly; hyperscaler capex disclosures naming Dutch sites (Microsoft Middenmeer, Google Eemshaven expansions)",
    "threshold": "NL self-build capacity additions exceeding NL colo additions in a calendar year",
    "updates": "increases"
   }
  ],
  "judgeTotal": 17,
  "distinctByJudge": "The claim is not 'geo.NL could be at band edge' — it attacks the apportionment method itself (euros-per-MW treated as constant), which the whyMissable field correctly notes no ledger source even measures. Docked one point because busway/self-build substitution appears elsewhere in the model (digest:seg-mix refs), so the coupling to geography is a clever recombination rather than a fully hidden discovery."
 }
]

